/**
 * Box component is basic for this library
 * @component
 *
 * @example
 * <Box>This is box component</Box>
 *
 * @example
 * <Box textColor="primary" d="flex">Flex and primary color</Box>
 *
 * @typedef {Object} BoxProps
 * @property {string} as - Change component type
 * @property {React.ReactNode} children - Add children components
 * @property {React.CSSProperty} style - Add other CSS syles
 * @property {Object|Array<string>|string} className - Add other class names
 *
 * @param {BoxProps} props
 * @return {JSX.Element} Box
 *
 * @author Sedelkov Egor [promethey] <sedelkovegor@gmail.com>
 * @version 1.0.0
 * @since 1.0.0
 */
const Box = React.forwardRef((props, ref) => {
  const {
    as: Component,
    style,
    children,
    className,

    d,
    display,
    dPrint,
    displayPrint,

    w,
    width,
    maxW,
    maxWidth,

    h,
    height,
    maxH,
    maxHeight,

    position,
    top,
    end,
    bottom,
    start,

    m,
    margin,
    mx,
    marginX,
    my,
    marginY,
    mt,
    marginTop,
    me,
    marginEnd,
    mb,
    marginBottom,
    ms,
    marginStart,

    p,
    padding,
    px,
    paddingX,
    py,
    paddingY,
    pt,
    paddingTop,
    pe,
    paddingEnd,
    pb,
    paddingBottom,
    ps,
    paddingStart,

    float,

    opacity,

    shadow,

    bgColor,
    bgGradient,
    bgOpacity,

    textColor,

    border,
    borderColor,
    borderOpacity,
    borderWidth,
    borderRadius,
    borderRadiusSize,

    visually,
    visible,
    invisible,

    clearFix,

    translateMiddle,

    textSelect,

    overflow,
    ...rest
  } = props;

  const classes = classNames(
    {
      [prefix("w", width || w)]: width || w,
      [prefix("mw", maxWidth || maxW)]: maxWidth || maxW,

      [prefix("h", height || h)]: height !== null || h !== null,
      [prefix("mh", maxHeight || maxH)]: maxHeight !== null || maxH !== null,

      [prefix("position", position)]: position,
      [prefix("top", top)]: top !== null,
      [prefix("end", end)]: end !== null,
      [prefix("bottom", bottom)]: bottom !== null,
      [prefix("start", start)]: start !== null,

      [prefix("opacity", opacity)]: opacity,

      [prefix("shadow", shadow)]: shadow,

      /** background */
      [prefix("bg", bgColor)]: bgColor,
      [prefix("bg", "gradient")]: bgGradient,
      [prefix("bg", "opacity", bgOpacity)]: bgOpacity,

      /** text color */
      [prefix("text", textColor)]: textColor,

      /** border */
      [prefix("border border", border)]: typeof border === "string",
      [prefix("border", borderWidth)]: borderWidth,
      [prefix("border", borderColor)]: borderColor,
      [prefix("border", borderOpacity)]: borderOpacity,
      [prefix("border", border)]:
        typeof border === "string" || typeof border === "number",
      border: typeof border === "boolean" && border,

      /** 'border-radius' style as 'rounded' classname */
      [prefix("rounded", borderRadius)]: typeof borderRadius === "string",
      [prefix("rounded", borderRadiusSize)]:
        typeof borderRadiusSize === "number",
      rounded: typeof borderRadius === "boolean",

      /**
       * if (visually === false) => 'visually-hidden'
       * else dynamic string 'visually-${visually}'
       */
      [prefix("visually", "hidden")]:
        typeof visually === "boolean" && !visually,
      [prefix("visually", visually)]: typeof visually === "string",

      /** 'hidden', 'scroll'... etc. */
      [prefix("overflow", overflow)]: overflow,

      /** 'visible' or 'invisible' */
      visible: visible && !invisible,
      invisible: invisible && !visible,

      /**
       * Clearfix utility
       * @see [@link https://getbootstrap.com/docs/5.3/helpers/clearfix/]
       */
      clearFix,

      /** Interactions: text selection */
      [prefix("user", "select", textSelect)]: textSelect,
    },
    classnames("d", d || display),
    classnames("d-print", dPrint || displayPrint),
    classnames("float", float),
    spacing("m", margin || m, marginX || mx, marginY || my, mt, me, mb, ms),
    spacing("p", padding || p, paddingX || px, paddingY || py, pt, pe, pb, ps),
    className,
    classnames("translate-middle", translateMiddle)
  );

  return (
    <Component ref={ref} style={style} className={classes} {...rest}>
      {children}
    </Component>
  );
});

Box.propTypes = propTypes;
Box.defaultProps = defaultProps;
Box.displayName = "Box";

export default Box;
